     handleMouseMoveA(event) {

      if (this._handlerType === 'resize') {
        this.handleResizeMove(event)
        this.$emit('resize', event, this.transform) // emit : 자식 컴포넌트에서 부모 컴포넌트로 데이터를 전달할 때 사용됩니다. resize라는 키를 등록
